$(document).ready(function(){$(".navbar-share").click("click",function(o){o.preventDefault(),$(".share-box").addClass("is-opened"),$("body").addClass("modal-open")}),$(".share-box-close").on("click",function(o){o.preventDefault(),$(".share-box").removeClass("is-opened"),$("body").removeClass("modal-open")}),$(window).scroll(function(){$(".hero").css("background-size",100+100*$(window).scrollTop()/3400+"%")}),$(".my-paroller").paroller()});